import React from 'react';

function Controls({ isAudioMuted, isVideoOff, toggleAudio, toggleVideo, leaveRoom, isHost }) {
  return (
    <div className="controls">
      <button 
        className={`control-btn ${isAudioMuted ? 'active' : ''}`}
        onClick={toggleAudio}
      >
        <i className={`fas fa-microphone${isAudioMuted ? '-slash' : ''}`}></i>
      </button>
      
      <button 
        className={`control-btn ${isVideoOff ? 'active' : ''}`}
        onClick={toggleVideo}
      >
        <i className={`fas fa-video${isVideoOff ? '-slash' : ''}`}></i>
      </button>
      
      {isHost && (
        <button className="control-btn host">
          <i className="fas fa-crown"></i>
        </button>
      )}
      
      <button className="control-btn leave" onClick={leaveRoom}>
        <i className="fas fa-phone-slash"></i>
      </button>
    </div>
  );
}

export default Controls;