import React, { useEffect, useRef, useState } from 'react';
import { useParams, useNavigate, useLocation } from 'react-router-dom';
import io from 'socket.io-client';
import Peer from 'simple-peer';
import VideoPlayer from './VideoPlayer';
import Controls from './Controls';
import './Room.css';

const socket = io({
  withCredentials: true,
  transports: ['websocket', 'polling']
});

function GuestRoom() {
  const { roomId } = useParams();
  const location = useLocation();
  const navigate = useNavigate();
  const [peers, setPeers] = useState([]);
  const [localStream, setLocalStream] = useState(null);
  const [isAudioMuted, setIsAudioMuted] = useState(false);
  const [isVideoOff, setIsVideoOff] = useState(false);
  const [loading, setLoading] = useState(true);
  
  const userVideo = useRef();
  const peersRef = useRef([]);
  
  const queryParams = new URLSearchParams(location.search);
  const guestName = queryParams.get('name') || 'Guest';

  useEffect(() => {
    let stream = null;
    let mounted = true;

    const initMedia = async () => {
      try {
        stream = await navigator.mediaDevices.getUserMedia({ video: true, audio: true });
        
        if (!mounted) return;
        
        setLocalStream(stream);
        if (userVideo.current) {
          userVideo.current.srcObject = stream;
        }

        // Join room
        socket.emit('join-room', {
          roomId,
          userId: `guest_${Date.now()}`,
          userName: guestName,
          role: 'participant'
        });

        setLoading(false);
      } catch (err) {
        console.error('Media error:', err);
        if (mounted) setLoading(false);
      }
    };

    initMedia();

    // Socket event handlers
    const handleExistingUsers = (users) => {
      if (!stream) return;
      const newPeers = [];
      users.forEach(user => {
        const peer = createPeer(user.socketId, stream);
        peersRef.current.push({
          peerId: user.socketId,
          peer,
          userName: user.userName
        });
        newPeers.push({
          peerId: user.socketId,
          peer,
          userName: user.userName
        });
      });
      setPeers(newPeers);
    };

    const handleUserConnected = (newUser) => {
      if (!stream) return;
      const peer = addPeer(newUser.socketId, stream);
      peersRef.current.push({
        peerId: newUser.socketId,
        peer,
        userName: newUser.userName
      });
      setPeers(prev => [...prev, {
        peerId: newUser.socketId,
        peer,
        userName: newUser.userName
      }]);
    };

    const handleOffer = ({ offer, fromSocketId }) => {
      if (!stream) return;
      const peer = addPeer(fromSocketId, stream);
      peer.signal(offer);
      peersRef.current.push({
        peerId: fromSocketId,
        peer,
        userName: 'Participant'
      });
      setPeers(prev => [...prev, {
        peerId: fromSocketId,
        peer,
        userName: 'Participant'
      }]);
    };

    socket.on('existing-users', handleExistingUsers);
    socket.on('user-connected', handleUserConnected);
    socket.on('offer', handleOffer);
    
    socket.on('answer', ({ answer, fromSocketId }) => {
      const peerItem = peersRef.current.find(p => p.peerId === fromSocketId);
      if (peerItem) peerItem.peer.signal(answer);
    });

    socket.on('ice-candidate', ({ candidate, fromSocketId }) => {
      const peerItem = peersRef.current.find(p => p.peerId === fromSocketId);
      if (peerItem) peerItem.peer.signal(candidate);
    });

    socket.on('user-disconnected', (socketId) => {
      const peerItem = peersRef.current.find(p => p.peerId === socketId);
      if (peerItem) peerItem.peer.destroy();
      peersRef.current = peersRef.current.filter(p => p.peerId !== socketId);
      setPeers(prev => prev.filter(p => p.peerId !== socketId));
    });

    return () => {
      mounted = false;
      socket.off('existing-users', handleExistingUsers);
      socket.off('user-connected', handleUserConnected);
      socket.off('offer', handleOffer);
      socket.off('answer');
      socket.off('ice-candidate');
      socket.off('user-disconnected');
      
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
      peersRef.current.forEach(({ peer }) => {
        if (peer && !peer.destroyed) peer.destroy();
      });
    };
  }, [roomId, guestName]);

  const createPeer = (targetSocketId, stream) => {
    const peer = new Peer({
      initiator: true,
      trickle: false,
      stream,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' }
        ]
      }
    });

    peer.on('signal', signal => {
      socket.emit('offer', { targetSocketId, offer: signal });
    });

    return peer;
  };

  const addPeer = (targetSocketId, stream) => {
    const peer = new Peer({
      initiator: false,
      trickle: false,
      stream,
      config: {
        iceServers: [
          { urls: 'stun:stun.l.google.com:19302' },
          { urls: 'stun:stun1.l.google.com:19302' }
        ]
      }
    });

    peer.on('signal', signal => {
      socket.emit('answer', { targetSocketId, answer: signal });
    });

    return peer;
  };

  const toggleAudio = () => {
    if (localStream) {
      const newMutedState = !isAudioMuted;
      localStream.getAudioTracks()[0].enabled = !newMutedState;
      setIsAudioMuted(newMutedState);
      socket.emit('toggle-audio', { roomId, isMuted: newMutedState });
    }
  };

  const toggleVideo = () => {
    if (localStream) {
      const newVideoState = !isVideoOff;
      localStream.getVideoTracks()[0].enabled = !newVideoState;
      setIsVideoOff(newVideoState);
      socket.emit('toggle-video', { roomId, isVideoOff: newVideoState });
    }
  };

  const leaveRoom = () => {
    if (localStream) {
      localStream.getTracks().forEach(track => track.stop());
    }
    navigate('/');
  };

  if (loading) return <div className="loading">Connecting to meeting...</div>;

  return (
    <div className="room-container">
      <div className="meeting-header">
        <div className="meeting-info">
          <h2>Guest Meeting</h2>
          <span className="room-id">ID: {roomId}</span>
        </div>
        <div className="participant-count">
          <i className="fas fa-users"></i>
          <span>{peers.length + 1}</span>
        </div>
      </div>

      <div className="video-grid">
        <div className="video-wrapper">
          <video
            ref={userVideo}
            autoPlay
            muted
            playsInline
            className={`video-element ${isVideoOff ? 'video-off' : ''}`}
          />
          <div className="video-overlay">
            <span className="user-name">
              {guestName} (You) <span className="guest-badge">Guest</span>
            </span>
            <div className="video-indicators">
              {isAudioMuted && <i className="fas fa-microphone-slash"></i>}
              {isVideoOff && <i className="fas fa-video-slash"></i>}
            </div>
          </div>
        </div>

        {peers.map((peer) => (
          <VideoPlayer
            key={peer.peerId}
            peer={peer.peer}
            userName={peer.userName}
          />
        ))}
      </div>

      <Controls
        isAudioMuted={isAudioMuted}
        isVideoOff={isVideoOff}
        toggleAudio={toggleAudio}
        toggleVideo={toggleVideo}
        leaveRoom={leaveRoom}
        isHost={false}
      />
    </div>
  );
}

export default GuestRoom;