import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import API from '../../services/api';
import './Meeting.css';

function CreateMeeting() {
  const [title, setTitle] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem('user'));

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const { data } = await API.post('/meetings/create', {
        title: title || `${user.name}'s Meeting`,
        password: password || null
      });
      
      // Show meeting links
      alert(`Meeting Created!\n\nRoom ID: ${data.roomId}\nHost Link: ${window.location.origin}/room/${data.roomId}?host=${user.id}\nParticipant Link: ${window.location.origin}/join/${data.roomId}`);
      
      navigate(`/room/${data.roomId}?host=${user.id}`);
    } catch (error) {
      alert('Failed to create meeting');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="create-meeting-container">
      <div className="create-meeting-card">
        <h2>Create New Meeting</h2>
        <p>Start a new video conference</p>
        
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Meeting Title (Optional)</label>
            <input
              type="text"
              value={title}
              onChange={(e) => setTitle(e.target.value)}
              placeholder={`${user?.name}'s Meeting`}
            />
          </div>
          
          <div className="form-group">
            <label>Password (Optional)</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter meeting password"
            />
          </div>
          
          <div className="form-actions">
            <button
              type="button"
              onClick={() => navigate('/')}
              className="cancel-btn"
            >
              Cancel
            </button>
            <button
              type="submit"
              disabled={loading}
              className="create-btn"
            >
              {loading ? 'Creating...' : 'Create Meeting'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
}

export default CreateMeeting;