import React, { useState, useEffect } from 'react';
import { useNavigate, useParams } from 'react-router-dom';
import API from '../../services/api';
import './Meeting.css';

function JoinMeeting() {
  const { roomId: urlRoomId } = useParams();
  const [roomId, setRoomId] = useState(urlRoomId || '');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    if (urlRoomId) {
      setRoomId(urlRoomId);
    }
  }, [urlRoomId]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    try {
      const { data } = await API.post('/meetings/validate', {
        roomId,
        password
      });
      
      // Navigate to guest room with name prompt
      const name = prompt('Enter your name:');
      if (name) {
        navigate(`/guest-room/${roomId}?name=${encodeURIComponent(name)}`);
      }
    } catch (err) {
      setError(err.response?.data?.message || 'Failed to join meeting');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="join-meeting-container">
      <div className="join-meeting-card">
        <h2>Join Meeting</h2>
        
        {error && <div className="error-message">{error}</div>}
        
        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label>Meeting ID</label>
            <input
              type="text"
              value={roomId}
              onChange={(e) => setRoomId(e.target.value)}
              placeholder="Enter meeting ID"
              required
              disabled={!!urlRoomId}
            />
          </div>
          
          <div className="form-group">
            <label>Password (if required)</label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter meeting password"
            />
          </div>
          
          <button
            type="submit"
            disabled={loading}
            className="join-btn"
          >
            {loading ? 'Joining...' : 'Continue'}
          </button>
        </form>
      </div>
    </div>
  );
}

export default JoinMeeting;